            if has(strong_joined, "공식 책임"):
                return "책임자 역할을 맡을 때는 권한과 결과 기록을 함께 남겨야 명예가 커집니다."
            if has(strong_joined, "평판"):
                return "한 번 얻은 신뢰를 오래 쓰려면 마무리, 약속, 기록을 흔들림 없이 지켜야 합니다."
