def _section_caution(section: dict[str, Any] | None, fallback: str = "주의점 확인") -> str:
    if not section:
        return fallback
    caution = str(section.get("caution_label") or "").strip()
    return _clean_caution_label(caution, fallback)


def _section_action(section: dict[str, Any] | None, fallback: str = "강점 확인") -> str:
    if not section:
        return fallback
    action = str(section.get("action_label") or "").strip()
    return action or fallback


def _top_section_action(top_sections: list[dict[str, Any]]) -> str:
    if not top_sections:
        return "강점 확인"
    return _section_action(top_sections[0])


def _top_section_caution(top_sections: list[dict[str, Any]]) -> str:
    for section in top_sections:
        caution = _section_caution(section, "")
        if caution:
            return caution
    return "무리한 확장 주의"


def _dynamic_honor_section(career: dict[str, Any] | None) -> dict[str, Any]:
    topic_items = _honor_topic_items(career)
    topics = _topic_lookup_by_title(topic_items)
    honor_topic = topics.get("공적 인정 기반", {}) or topics.get("사회적 인정이 붙는 자리", {}) or topics.get("사회적 인정도", {})
    reputation_topic = topics.get("평판 지속력", {}) or topics.get("평판 유지력", {}) or topics.get("평판이 오래 남는 힘", {})
    formal_topic = topics.get("공식 책임 수행력", {}) or topics.get("공식 책임", {}) or topics.get("공식 책임을 맡는 힘", {})
    management_topic = topics.get("명예를 지켜내는 기준", {}) or topics.get("명예 관리", {})
    lead_label, lead_value = _best_section_axis(
        career,
        [
            ("recognition", "사회적 인정도", 8),
            ("career_achievement", "직업 성취력", 5),
            ("organization_fit", "조직 안에서 자리 잡는 힘", 4),
            ("responsibility_capacity", "책임 수행력", 3),
            ("expertise", "전문성", 1),
        ],
    )
    recognition = _section_axis_value(career, "recognition")
    achievement = _section_axis_value(career, "career_achievement")
    organization = _section_axis_value(career, "organization_fit")
    caution = _section_caution(career, "책임 대비 권한 부족")
    strongest = _strongest_topic(topic_items)
    strongest_title = str(strongest.get("title") or "")
    if strongest_title in {"공적 인정 기반", "사회적 인정도", "사회적 인정이 붙는 자리"}:
        main_sentence = "당신은 이름이 기록되는 책임 자리에서 명예가 올라가는 사주입니다."
    elif strongest_title in {"평판 지속력", "평판 유지력", "평판이 오래 남는 힘"}:
        main_sentence = "당신의 명예운은 오래 쌓은 신뢰가 다음 제안으로 돌아오는 쪽입니다."
    elif strongest_title in {"공식 책임 수행력", "공식 책임", "공식 책임을 맡는 힘"}:
        main_sentence = "당신은 책임자 위치에 설 때 이름과 평판이 함께 올라갑니다."
    else:
        main_sentence = "당신의 명예운은 평판을 지키면서 책임의 크기를 키워가는 쪽입니다."
    support_sentence = str(strongest.get("body") or "").strip()
    if _grade_strength(lead_value) <= 2 and lead_label == "전문성":
        support_sentence = "빠른 주목보다 전문 분야와 책임 이력이 쌓일수록 명예가 강해집니다."
    management_score = int(management_topic.get("score") or 0)
    management_title = "명예를 지키는 방식" if management_score >= 58 else "평판을 깎는 자리"
    return _premium_section(
        "premium-honor",
        domain="honor",
        domain_label="명예운",
        heading="명예운",
        lead=main_sentence,
        narrative=f"{support_sentence} {management_topic.get('body', '책임 범위가 흐려지면 평판이 먼저 흔들립니다.')}",
        checkpoints=[
            f"공적 인정 기반: {recognition}",
            f"직업 성취력: {achievement}",
            f"공적 인정 기반: {_section_axis_value(career, 'recognition')}",
            f"전문성: {_section_axis_value(career, 'expertise')}",
            f"조직 안에서 자리 잡는 힘: {organization}",
            f"주의점: {caution}",
        ],
        detail_blocks=[
            _detail_block(
                "공적 인정 기반",
                str(honor_topic.get("body") or support_sentence),
                ["공개 평가처럼 이름이 기록되는 자리에서 강합니다.", "전문성이 검증되는 자리일수록 책임도 함께 붙습니다."],
            ),
            _detail_block(
                "직책 상승 가능성",
                str(formal_topic.get("body") or "책임자처럼 역할이 기록되는 자리에서 평판이 강해집니다."),
                ["권한이 붙은 책임 자리에서 명예가 붙습니다.", "권한 없이 책임만 맡는 자리는 평판보다 소모가 남습니다."],
                tone="strong" if int(formal_topic.get("score") or 0) >= 76 else "",
            ),
            _detail_block(
                "평판 지속 방식",
                str(reputation_topic.get("body") or "꾸준한 이력이 평판을 지켜줍니다."),
                ["말로 한 약속보다 기록이 평판을 지킵니다."],
            ),
            _detail_block(
                management_title,
                str(management_topic.get("body") or "책임에 비해 권한이 좁은 자리는 인정과 부담이 함께 남습니다."),
                [f"{_with_particle(caution, '이', '가')} 드러나는 자리에서는 책임 소재가 흐려집니다. 이때는 인정받는 속도보다 평판 손상이 더 빠르게 남습니다."],
                tone="risk" if management_score < 58 else "",
            ),
        ],
        topic_items=topic_items,
        feature_axes=_merged_feature_axes_from_sections(career),
    )


def _dynamic_social_section(
    love: dict[str, Any] | None,
    marriage: dict[str, Any] | None,
    money: dict[str, Any] | None,
) -> dict[str, Any]:
    topic_items = _social_topic_items(love, marriage, money)
    topics = _topic_lookup_by_title(topic_items)
    people_topic = topics.get("인맥 형성력", {}) or topics.get("사람을 얻는 방식", {}) or topics.get("사람을 얻는 힘", {})
    support_topic = topics.get("도움으로 이어지는 인연", {}) or topics.get("도움이 되는 사람", {})
    sustain_topic = topics.get("관계가 오래 남는 힘", {}) or topics.get("관계 지속력", {})
    boundary_topic = topics.get("부탁과 책임의 경계", {}) or topics.get("부탁과 책임", {})
    lead_label, lead_value = _best_section_axis(
        love,
        [
            ("relationship_opening", "인연 형성력", 6),
            ("stability", "관계 안정성", 7),
            ("expression", "표현력", 5),
            ("boundary", "관계 조절력", 4),
            ("recovery", "갈등 회복력", 1),
        ],
    )
    opening = _section_axis_value(love, "relationship_opening")
    stability = _section_axis_value(love, "stability")
    boundary = _section_axis_value(love, "boundary")
    shared_money = _section_axis_value(money, "shared_asset_risk", "")
    money_caution = _section_caution(money, "")
    love_caution = _section_caution(love, "표현 거리감")
    if shared_money in {"주의", "높음"} or "정산" in money_caution or "몫" in money_caution:
        caution = "금전·역할 혼선 주의"
    else:
        caution = love_caution
    family = _section_axis_value(marriage, "responsibility_share")
    strongest = _strongest_topic(topic_items)
    strongest_title = str(strongest.get("title") or "")
    if strongest_title in {"관계 지속력", "관계가 오래 남는 힘"}:
        main_sentence = "당신은 넓은 인맥보다 오래 남는 사람을 통해 운이 열리는 사주입니다."
    elif strongest_title in {"도움이 되는 사람", "도움으로 이어지는 인연"}:
        main_sentence = "당신의 대인관계운은 말뿐인 친분보다 실제 제안으로 들어오는 인연이 강합니다."
    elif strongest_title in {"인맥 형성력", "사람을 얻는 방식", "사람을 얻는 힘"}:
        main_sentence = "당신은 필요한 사람을 알아보고 오래 남는 관계로 만드는 능력이 있습니다."
    else:
        main_sentence = "당신의 대인관계는 부탁과 책임의 선을 분명히 할수록 오래 갑니다."
    support_sentence = str(strongest.get("body") or "").strip()
    if caution == "금전·역할 혼선 주의":
        final_sentence = "가까운 사이에 금전 관계가 들어오면 배신감이나 손해가 남습니다."
    else:
        final_sentence = "가까운 사이일수록 금전 부탁을 구두 약속으로 처리하면 부담이 남습니다."
    if _grade_strength(boundary) <= 1:
        support_sentence = "가까워질수록 부탁과 책임이 섞입니다."
        final_sentence = "처음부터 부탁의 범위와 거절 기준이 분명해야 합니다."
    boundary_topic_score = int(boundary_topic.get("score") or 0)
    boundary_title = "부탁과 책임의 선" if boundary_topic_score >= 58 else "부탁이 부담으로 바뀌는 지점"
    return _premium_section(
        "premium-social",
        domain="social",
        domain_label="대인관계운",
        heading="대인관계운",
        lead=main_sentence,
        narrative=f"{support_sentence} {final_sentence}",
        checkpoints=[
            f"인연 형성력: {opening}",
            f"관계가 오래 가는 힘: {stability}",
            f"관계 조절력: {boundary}",
            f"갈등 회복력: {_section_axis_value(love, 'recovery')}",
            f"애정 표현력: {_section_axis_value(love, 'expression')}",
            f"가까운 관계 책임: {family}",
            f"주의점: {caution}",
        ],
        detail_blocks=[
            _detail_block(
                "신뢰 형성 방식",
                str(people_topic.get("body") or support_sentence),
                ["넓은 모임보다 오래 본 사람, 반복해서 협업한 사람이 실질적인 조력이 됩니다.", "인맥은 규모보다 결정적인 순간에 실질적인 지원을 하는 사람이 값어치를 가집니다."],
            ),
            _detail_block(
                "실질 조력자",
                str(support_topic.get("body") or "오래 신뢰한 사람이 현실적인 도움을 줍니다."),
                ["조언보다 실제 소개를 해주는 사람이 귀합니다.", "오래 본 관계에서 결정적인 소개가 들어옵니다."],
            ),
            _detail_block(
                "관계 지속 방식",
                str(sustain_topic.get("body") or "검증된 관계는 오래 남습니다."),
                ["서로의 역할과 거리가 분명할수록 관계가 오래 갑니다."],
            ),
            _detail_block(
                boundary_title,
                str(boundary_topic.get("body") or final_sentence),
                ["부탁을 한 번 받아주면 다음에는 당연한 책임처럼 돌아올 수 있습니다."],
                tone="risk" if boundary_topic_score < 58 else "",
            ),
        ],
        topic_items=topic_items,
        feature_axes=_merged_feature_axes_from_sections(love, marriage, money),
    )


def _premium_detail_domains_for_section(section: dict[str, Any]) -> tuple[str, ...]:
    section_id = str(section.get("section_id") or "")
    domain = str(section.get("domain") or "")
    heading = str(section.get("heading") or "")
    label = f"{section_id} {domain} {heading} {section.get('domain_label') or ''}"
    if "love-marriage" in section_id:
        return ("love", "marriage")
    if domain in {"love", "marriage"}:
        return (domain,)
    if "연애" in label:
        return ("love",)
    if "결혼" in label:
        return ("marriage",)
    if "good-timing" in section_id or domain == "timing" or "좋은 시기" in label:
        return ("timing",)
    if "life-stages" in section_id or domain == "life" or "초년" in label:
        return ("life_period",)
    if "personality" in section_id or domain == "personality" or "성향" in label or "성격" in label:
        return ("personality",)
    if "honor" in section_id or domain == "honor" or "명예" in label:
        return ("honor",)
    if "social" in section_id or domain == "social" or "대인" in label:
        return ("social",)
    if domain in {"money", "career"}:
        return (domain,)
    return (domain,) if domain else ()


def _polish_premium_detail_judgment(domain: str, title: str, judgment: str) -> str:
    text = " ".join(str(judgment or "").split())
    exact_replacements = {
        "기술과 결과물이 매출의 근거가 됩니다.": "기술과 결과물이 단가를 얻으면서 수입의 근거가 됩니다.",
        "큰 수익을 노린 투자는 손실 폭이 크게 벌어집니다.": "수익률만 보고 들어간 거래는 회수 단계에서 크게 흔들릴 수 있습니다.",
        "계약서를 남기지 않은 돈은 회수 과정에서 손실이 납니다.": "서류 없이 움직인 돈은 회수 단계에서 불리하게 남습니다.",
        "재산이 커질수록 배우자나 가족이 권리를 주장합니다.": "재산이 커질수록 가족이나 배우자와 명의, 몫의 문제가 예민해집니다.",
        "전문성으로 이름을 얻는 직업운입니다.": "전문성이 직업적 신뢰와 단가로 이어지는 운입니다.",
        "여러 이해관계가 얽힌 일을 정리해 조직의 방향을 잡는 자리에서 강합니다.": "여러 이해관계가 얽힌 일을 정리하고 운영 기준을 세우는 자리에서 강합니다.",
        "처음에는 좋은 조건처럼 보이지만 손실이 납니다.": "처음에는 유리해 보여도 회수 조건이 약하면 손실로 남습니다.",
        "마음이 있어도 결혼 결정은 늦게 굳어집니다.": "마음이 있어도 주거와 가족 문제가 걸리면 결혼 결정이 늦어집니다.",
        "결혼운은 감정이 생활 계획으로 넘어갈 때 강해집니다.": "결혼운은 감정이 집, 돈, 일정의 문제로 넘어갈 때 현실화됩니다.",
        "생활 기준이 분명해지면 결혼 이야기가 빠르게 구체화됩니다.": "생활 기준이 분명해지면 결혼은 말보다 절차로 빨리 움직입니다.",
        "전문성으로 이름을 얻는 직업운입니다": "전문성이 직업적 신뢰와 단가로 이어지는 운입니다.",
    }
    if text in exact_replacements:
        return exact_replacements[text]
    replacements = (
        ("이름을 얻는 직업운입니다", "직업적 신뢰와 단가로 이어지는 운입니다"),
        ("매출의 근거가 됩니다", "수입의 근거가 됩니다"),
        ("권리를 주장합니다", "명의와 몫의 문제가 예민해집니다"),
        ("회수 과정에서 손실이 납니다", "회수 단계에서 불리하게 남습니다"),
        ("손실 폭이 크게 벌어집니다", "회수 단계에서 크게 흔들릴 수 있습니다"),
        ("마음은 깊지만 표현이 늦으면", "마음이 깊어도 표현이 늦으면"),
        ("일상과 돈까지 흔들립니다", "일상과 금전 감각까지 흔들립니다"),
        ("결혼 생활이 오래 어렵습니다", "결혼 생활의 안정이 오래 흔들립니다"),
        ("결정권을 놓고 강하게 부딪힙니다", "결정권 문제로 정면 충돌할 수 있습니다"),
    )
    for before, after in replacements:
        text = text.replace(before, after)
    if domain == "money" and title and text == title:
        return "금전 운세에서 실제 손익을 결정하는 기준입니다."
    return text


def _normalize_premium_detail(detail: dict[str, Any]) -> dict[str, Any]:
    def clean_detail_text(value: Any) -> str:
        return (
            str(value or "")
            .strip()
            .replace("좋은 연도의 사건화", "좋은 연도에 드러나는 일")
            .replace("주의 연도의 손실 사건", "주의 연도에 관리할 일")
            .replace("좋은 연도에는 계약, 승진, 자산 취득처럼 결과가 남습니다.", "좋은 연도에는 계약, 승진, 자산 확보가 두드러집니다.")
            .replace("주의 연도에는 돈, 계약, 관계 중 하나가 크게 흔들립니다.", "주의 연도에는 금전, 계약, 관계에서 관리할 일이 생깁니다.")
            .replace("결혼 논의 지연", "결혼 준비 지연")
            .replace("결혼 논의", "결혼 준비")
            .replace("손실 사건", "관리할 일")
            .replace("손실 지점", "주의점")
        )

    domain_text = str(detail.get("domain") or "")
    title = clean_detail_text(detail.get("title"))
    judgment = _polish_premium_detail_judgment(
        domain_text,
        title,
        clean_detail_text(detail.get("judgment")),
    )
    scenes = [
        clean_detail_text(scene)
        for scene in detail.get("event_scenes", [])
        if clean_detail_text(scene)
    ][:3]
    notes = [
        clean_detail_text(note)
        for note in detail.get("premium_notes", [])
        if clean_detail_text(note)
    ][:2]
    caution_targets = [
        clean_detail_text(target)
        for target in detail.get("caution_targets", [])
        if clean_detail_text(target)
    ][:3]
    level = _premium_detail_level(
        str(detail.get("level") or ""),
        title=title,
        judgment=judgment,
    )
    return {
        "entry_key": str(detail.get("entry_key") or ""),
        "domain": domain_text,
        "title": title,
        "score": int(detail.get("score") or 0),
        "level": level,
        "judgment": judgment,
        "event_scenes": scenes,
        "premium_notes": notes,
        "caution_targets": caution_targets,
        "timing_keywords": [
            clean_detail_text(keyword)
            for keyword in detail.get("timing_keywords", [])
            if clean_detail_text(keyword)
        ][:3],
    }


def _premium_detail_level(source_level: str, *, title: str, judgment: str) -> str:
    level = str(source_level or "").strip().lower()
    if level in {"risk", "watch", "caution"}:
        return "watch"
    text = f"{title} {judgment}"
    watch_markers = (
        "손실",
        "손상",
        "불균형",
        "압박",
        "부담",
        "소모",
        "늦",
        "덜 남",
        "나뉘",
        "줄어",
        "줄어듭",
        "넘어갑",
        "넘어오",
        "흔들",
        "말이 달라",
        "부딪",
        "침범",
        "채무",
        "보증",
        "권리 주장",
        "명의 대여",
        "말로 정한 약속",
        "섞이는 재산",
        "공동 투자",
        "회수 과정",
        "손해",
        "손익이 흐려",
        "기준 없는 조직",
        "책임 전가",
        "공을 빼앗",
        "사생활",
        "감정 기복",
        "경력에 흠",
        "충돌",
        "갈등",
        "부부 사이",
        "가족의 돈",
        "가족 지원",
        "가족 책임",
        "명의 갈등",
        "부양 부담",
        "결정권을 놓고",
        "지나간 서운함",
        "평판 손상",
        "견제",
        "당신 몫으로 굳",
    )
    if any(marker in text for marker in watch_markers):
        return "watch"
    return level or "neutral"


def _section_topic_strength(section: dict[str, Any], *titles: str) -> int:
    wanted = {_compact_match_key(title) for title in titles if title}
    if not wanted:
        return 0
    best = 0
    for item in section.get("topic_items") or []:
        if not isinstance(item, dict):
            continue
        title = _compact_match_key(item.get("title"))
        if title in wanted:
            score = item.get("score")
            if isinstance(score, int):
                best = max(best, score)
            else:
                best = max(best, _section_value_strength(str(item.get("value") or "")))
    return best


def _premium_detail_conflicts_with_section(detail: dict[str, Any], section: dict[str, Any]) -> bool:
    title = str(detail.get("title") or "")
    domains = set(_premium_detail_domains_for_section(section))
    if domains == {"career"}:
        recognition_power = _section_topic_strength(section, "업무 평가력", "평가가 따라오는 자리")
        organization_power = _section_topic_strength(section, "조직 적합도", "조직 안에서 자리 잡는 힘")
        authority_power = _section_topic_strength(section, "권한·책임 균형도", "권한과 책임의 균형")
        all_strong = min(recognition_power or 100, organization_power or 100, authority_power or 100) >= 80
        if authority_power >= 80 and "책임과 결정권의 불균형" in title:
            return True
        if recognition_power >= 80 and "공을 빼앗기는 조직 자리" in title:
            return True
        if (organization_power >= 80 or all_strong) and "기준 없는 조직에서의 소모" in title:
            return True
    if domains == {"love", "marriage"} or domains == {"love"} or domains == {"marriage"}:
        marriage_power = _section_topic_strength(section, "결혼 연결력", "혼인 성향", "결혼 안정성", "결혼이 안정되는 힘")
        relationship_power = _section_topic_strength(section, "관계 안정성", "관계가 오래 가는 힘")
        expression_power = _section_topic_strength(section, "애정 표현력", "애정이 표현되는 방식")
        if marriage_power >= 74 and "결혼 판단이 늦어지는 자리" in title:
            return True
        if relationship_power >= 80 and "지나간 서운함이 돌아오는 시기" in title:
            return True
        if expression_power >= 80 and "표현" in title and "늦" in title:
            return True
    return False


def _premium_detail_display_metric(title: str, domain: str, level: str, raw_score: Any) -> dict[str, Any]:
    if not isinstance(raw_score, int):
        return {}
    display_score = max(0, min(100, raw_score))
    metric_label = title
    if level in {"watch", "risk", "caution"}:
        display_score = max(28, min(62, round(100 - display_score * 0.7)))
        text = f"{domain} {title}"
        if domain == "marriage" and any(marker in text for marker in ("결혼", "생활", "주거", "부부", "배우자", "가족")):
            metric_label = "생활 조율력"
        elif any(marker in text for marker in ("계약", "문서", "약속", "정산", "회수")):
            metric_label = "계약·문서 안정성"
        elif any(marker in text for marker in ("투자", "변동", "손실", "보증", "채무")):
            metric_label = "투자·거래 안정성"
        elif any(marker in text for marker in ("공동", "가족", "배우자", "명의", "지분")):
            metric_label = "공동 자금 운영력"
        elif any(marker in text for marker in ("권한", "결정권", "책임", "조직")):
            metric_label = "권한 확보력"
        elif any(marker in text for marker in ("표현", "연락", "서운", "감정", "거리")):
            metric_label = "관계 조율력"
    level_label = _contract_level_from_score(display_score)
    return {
        "metric_key": _compact_match_key(title),
        "metric_label": metric_label,
        "score": display_score,
        "level": level_label,
        "value": level_label,
    }


def _section_metric_match_pool(section: dict[str, Any]) -> list[dict[str, Any]]:
    pool: list[dict[str, Any]] = []
    for source in ("representative_metrics", "feature_axes", "topic_items"):
        for item in section.get(source) or []:
            if not isinstance(item, dict):
                continue
            label = str(item.get("label") or item.get("title") or "").strip()
            if not label:
                continue
            score = item.get("score")
            next_item = {
                "label": label,
                "key": str(item.get("key") or item.get("metric_key") or "").strip(),
                "source": source,
                "score": score if isinstance(score, int) else _score_from_axis_value(item.get("value")),
                "text": " ".join(
                    str(value)
                    for value in (
                        label,
                        item.get("key"),
                        item.get("metric_key"),
                        item.get("source_title"),
                        item.get("body"),
                        item.get("definition"),
                    )
                    if value
                ),
            }
            components = item.get("judgment_components")
            if isinstance(components, dict):
                extra_terms: list[str] = []
                for component_key in (
                    "engine_metric_label",
                    "engine_metric_key",
                    "cycle_tags",
                    "principle_tags",
                    "gyeokguk_action_titles",
                    "layer_coverage",
                ):
                    value = components.get(component_key)
                    if isinstance(value, list):
                        extra_terms.extend(str(entry) for entry in value if entry)
                    elif value:
                        extra_terms.append(str(value))
                if extra_terms:
                    next_item["text"] = f"{next_item['text']} {' '.join(extra_terms)}"
            pool.append(next_item)
    return pool


def _premium_detail_section_match_score(detail: dict[str, Any], section: dict[str, Any]) -> float:
    title = str(detail.get("title") or "").strip()
    domain = str(detail.get("domain") or _domain_key(section) or "").strip()
    level = str(detail.get("level") or "").strip()
    raw_score = detail.get("score")
    display_metric = _premium_detail_display_metric(title, domain, level, raw_score)
    display_label = str(display_metric.get("metric_label") or title).strip()
    detail_text = " ".join(
        str(value)
        for value in (
            title,
            display_label,
            detail.get("judgment"),
            " ".join(str(item) for item in detail.get("event_scenes") or [] if item),
            " ".join(str(item) for item in detail.get("premium_notes") or [] if item),
            " ".join(str(item) for item in detail.get("caution_targets") or [] if item),
        )
        if value
    )
    detail_key = _compact_match_key(detail_text)
    display_key = _compact_match_key(display_label)
    title_key = _compact_match_key(title)
    match_pool = _section_metric_match_pool(section)
    score = min(36.0, max(0, float(raw_score or 0)) * 0.36)

    strong_label = _compact_match_key(section.get("strong_metric_label"))
    watch_label = _compact_match_key(section.get("watch_metric_label"))
    is_watch = level in {"watch", "risk", "caution"}

    for metric in match_pool:
        metric_label = str(metric.get("label") or "")
        metric_key = _compact_match_key(metric_label)
        metric_text_key = _compact_match_key(metric.get("text"))
        metric_score = metric.get("score")
        if not isinstance(metric_score, int):
            metric_score = 58
        direct = bool(
            (display_key and metric_key and (display_key == metric_key or display_key in metric_key or metric_key in display_key))
            or (title_key and metric_key and (title_key == metric_key or title_key in metric_key or metric_key in title_key))
        )
        contextual = bool(
            detail_key
            and metric_text_key
            and (
                detail_key in metric_text_key
                or metric_text_key in detail_key
                or any(
                    len(token) >= 3 and token in metric_text_key
                    for token in re.split(r"[\s·ㆍ,\./]+", detail_text)
                )
            )
        )
        if not direct and not contextual:
            continue
        if is_watch:
            score += max(0, 76 - metric_score) * (0.95 if direct else 0.42)
            if metric_key and metric_key == watch_label:
                score += 28
        else:
            score += max(0, metric_score - 48) * (0.82 if direct else 0.34)
            if metric_key and metric_key == strong_label:
                score += 24
        if metric.get("source") == "representative_metrics":
            score += 10
        elif metric.get("source") == "feature_axes":
            score += 6

    if is_watch and watch_label and (watch_label in display_key or display_key in watch_label or watch_label in title_key):
        score += 18
    if not is_watch and strong_label and (strong_label in display_key or display_key in strong_label or strong_label in title_key):
        score += 16
    return score


def _attach_premium_detail_sections(
    section: dict[str, Any],
    premium_detail_sections: list[dict[str, Any]],
) -> dict[str, Any]:
    domains = set(_premium_detail_domains_for_section(section))
    if not domains:
        return section
    if domains == {"personality"}:
        return section
    if domains == {"timing"}:
        return section
    details = []
    for detail in premium_detail_sections:
        if not isinstance(detail, dict) or str(detail.get("domain") or "") not in domains:
            continue
        normalized = _normalize_premium_detail(detail)
        if _premium_detail_conflicts_with_section(normalized, section):
            continue
        details.append(normalized)
    detail_limit = 3
    if domains == {"money"} or domains == {"career"}:
        detail_limit = 4
    details = sorted(
        details,
        key=lambda item: (
            -_premium_detail_section_match_score(item, section),
            -int(item.get("score") or 0),
            str(item.get("title") or ""),
        ),
    )[:detail_limit]
    if not details:
        return section
    enriched = dict(section)
    enriched["premium_details"] = details

    def detail_block_from_detail(detail: dict[str, Any]) -> dict[str, Any] | None:
        title = str(detail.get("title") or "").strip()
        judgment = str(detail.get("judgment") or "").strip()
        scenes = [
            str(scene).strip()
            for scene in detail.get("event_scenes", [])
            if str(scene or "").strip()
        ][:3]
        if not title or not judgment:
            return None
        score = detail.get("score")
        return _detail_block(
            title,
            judgment,
            scenes,
            tone=str(detail.get("level") or ""),
            metric=_premium_detail_display_metric(
                title,
                str(detail.get("domain") or ""),
                str(detail.get("level") or ""),
                score,
            ),
        )

    detail_blocks = [
        block
        for block in (detail_block_from_detail(detail) for detail in details)
        if isinstance(block, dict)
    ]
    existing_blocks = list(enriched.get("detail_blocks") or [])
    if domains & {"money", "career", "love", "marriage"}:
        ordered_blocks = detail_blocks + existing_blocks
    else:
        ordered_blocks = existing_blocks + detail_blocks

    deduped_blocks: list[dict[str, Any]] = []
    seen_titles: set[str] = set()
    for block in ordered_blocks:
        title = str(block.get("title") or "").strip()
        key = _compact_match_key(title)
        if key and key in seen_titles:
            continue
        if key:
            seen_titles.add(key)
        deduped_blocks.append(block)
    if deduped_blocks:
        enriched["detail_blocks"] = _enrich_detail_block_actions(
            next(iter(domains)) if len(domains) == 1 else _domain_key(enriched),
            deduped_blocks,
        )
    existing = list(enriched.get("checkpoints") or [])
    for detail in details[:2]:
        title = str(detail.get("title") or "")
        judgment = str(detail.get("judgment") or "")
        if title and judgment:
            existing.append(f"{title}: {judgment}")
    enriched["checkpoints"] = existing
    return enriched


def _premium_visual_profile(section: dict[str, Any]) -> dict[str, Any]:
    domain = _domain_key(section)
    config = premium_category_contract(domain)
    topics = [topic for topic in section.get("topic_items") or [] if isinstance(topic, dict)]
    if not config or not topics:
        return {}
    by_title = {str(topic.get("title") or ""): topic for topic in topics}
    display_labels = config.get("display_labels") or {}
    picked: list[dict[str, Any]] = []
    for title in config.get("visual_slots", ()):
        topic = by_title.get(str(title))
        if topic:
            picked.append(topic)
    for topic in topics:
        if len(picked) >= 3:
            break
        if topic not in picked:
            picked.append(topic)
    items: list[dict[str, Any]] = []
    for topic in picked[:3]:
        source_label = str(topic.get("title") or "").strip()
        label = str(display_labels.get(source_label, source_label)).strip()
        value = str(topic.get("value") or "").strip()
        body = str(topic.get("body") or topic.get("definition") or "").strip()
        if not label:
            continue
        item: dict[str, Any] = {
            "label": label,
            "source_title": source_label,
            "value": value or "확인",
            "caption": body,
            "tone": str(topic.get("tone") or "neutral"),
        }
        if topic.get("score") is not None:
            item["score"] = topic.get("score")
        items.append(item)
    if not items:
        return {}
    return {
        "label": str(config.get("visual_label") or config.get("section_label") or ""),
        "headline": str(config.get("visual_headline") or ""),
        "items": items,
    }


PREMIUM_SCREEN_ITEM_CONTRACT_SCHEMA_VERSION = "premium_screen_item_contract_v1"


def _premium_screen_contract_text(value: Any) -> str:
    return _replace_premium_display_terms(str(value or "").strip())


def _premium_screen_score_payload(score: Any) -> dict[str, Any]:
    if not isinstance(score, int):
        return {}
    return {
        "score": score,
        "level": _contract_level_from_score(score),
        "value": _score_value(score),
        "tone": _topic_tone_from_score(score),
    }


def _premium_screen_item_contract(section: dict[str, Any]) -> dict[str, Any]:
    """Expose expert judgments as a screen-consumable category contract.

    The analysis engine can keep growing in depth, but the product screen needs
    a stable contract: what to show first, which judgment each slot represents,
    and which engine basis supports it. This function is intentionally
    renderer-neutral so mobile, web, and later app surfaces can consume the same
    structure.
    """

    domain = _domain_key(section)
    category_contract = (
        section.get("category_contract")
        if isinstance(section.get("category_contract"), dict)
        else {}
    )
    visual_profile = (
        section.get("visual_profile")
        if isinstance(section.get("visual_profile"), dict)
        else _premium_visual_profile(section)
    )
    section_verdict = (
        section.get("section_verdict")
        if isinstance(section.get("section_verdict"), dict)
        else {}
    )
    if not category_contract and not visual_profile and not section_verdict:
        return {}

    summary_slots: list[dict[str, Any]] = []
    verdict_score = section.get("total_score")
    if not isinstance(verdict_score, int):
        verdict_score = section_verdict.get("score")
    verdict_slot: dict[str, Any] = {
        "slot": "domain_verdict",
        "label": "전체 결론",
        "title": _premium_screen_contract_text(section.get("title") or category_contract.get("section_label")),
        "body": _premium_screen_contract_text(
            section_verdict.get("interpretation")
            or section.get("summary")
            or section.get("lead")
        ),
        "target": "domain-verdict",
        "source": "section_verdict",
    }
    verdict_slot.update(_premium_screen_score_payload(verdict_score))
    if verdict_slot.get("title") or verdict_slot.get("body") or verdict_slot.get("score") is not None:
        summary_slots.append(verdict_slot)

    for index, item in enumerate(list((visual_profile or {}).get("items") or []), start=1):
        if not isinstance(item, dict):
            continue
        label = _premium_screen_contract_text(item.get("label"))
        if not label:
            continue
        next_item: dict[str, Any] = {
            "slot": f"visual_{index}",
            "label": label,
            "title": label,
            "body": _premium_screen_contract_text(item.get("caption")),
            "target": "domain-core-metrics" if index <= 2 else "domain-detail-metrics",
            "source": "visual_profile",
            "source_title": _premium_screen_contract_text(item.get("source_title")),
        }
        value = _premium_screen_contract_text(item.get("value"))
        if value:
            next_item["value"] = value
        next_item.update(_premium_screen_score_payload(item.get("score")))
        summary_slots.append(next_item)

    target_by_slot = {
        "opening": "domain-verdict",
        "primary_profile": "domain-core-metrics",
        "behavior_scene": "domain-interpretation",
        "strength_metric": "domain-core-metrics",
        "management_metric": "domain-detail-metrics",
        "timing_or_transition": "domain-interpretation",
    }
    screen_items: list[dict[str, Any]] = []
    for item in list(category_contract.get("content_plan") or []):
        if not isinstance(item, dict):
            continue
        slot = _premium_screen_contract_text(item.get("slot"))
        label = _premium_screen_contract_text(item.get("label"))
        if not slot or not label:
            continue
        next_item = {
            "slot": slot,
            "label": label,
            "purpose": _premium_screen_contract_text(item.get("purpose")),
            "result": _premium_screen_contract_text(item.get("result") or item.get("purpose")),
            "source": _premium_screen_contract_text(item.get("source")),
            "visual_role": _premium_screen_contract_text(item.get("visual_role")),
            "linked_topic": _premium_screen_contract_text(item.get("linked_topic")),
            "target": target_by_slot.get(slot, "domain-interpretation"),
        }
        value = _premium_screen_contract_text(item.get("value"))
        if value:
            next_item["value"] = value
        evidence = _premium_screen_contract_text(item.get("evidence"))
        if evidence:
            next_item["evidence"] = evidence
        next_item.update(_premium_screen_score_payload(item.get("score")))
        screen_items.append(next_item)

    if not screen_items:
        for index, unit in enumerate(list(category_contract.get("reading_units") or [])[:6], start=1):
            if not isinstance(unit, dict):
                continue
            label = _premium_screen_contract_text(unit.get("display_label") or unit.get("label"))
            if not label:
                continue
            next_item = {
                "slot": f"reading_{index}",
                "label": label,
                "purpose": _premium_screen_contract_text(unit.get("focus")),
                "result": _premium_screen_contract_text(unit.get("result") or unit.get("focus")),
                "source": "reading_units",
                "linked_topic": _premium_screen_contract_text(unit.get("topic")),
                "target": "domain-core-metrics" if index <= 3 else "domain-detail-metrics",
            }
            value = _premium_screen_contract_text(unit.get("value"))
            if value:
                next_item["value"] = value
            next_item.update(_premium_screen_score_payload(unit.get("score")))
            screen_items.append(next_item)

    expert_axes: list[dict[str, Any]] = []
    for raw_axis in list(category_contract.get("judgment_axes") or [])[:10]:
        if not isinstance(raw_axis, dict):
            continue
        title = _premium_screen_contract_text(raw_axis.get("title") or raw_axis.get("label"))
        if not title:
            continue
        expert_axes.append(
            {
                "key": _premium_screen_contract_text(raw_axis.get("key") or _compact_match_key(title)),
                "title": title,
                "customer_question": _premium_screen_contract_text(raw_axis.get("customer_question")),
                "verdict_axis": _premium_screen_contract_text(raw_axis.get("verdict_axis")),
                "engine_basis": _premium_screen_contract_text(raw_axis.get("engine_basis")),
                "premium_output": _premium_screen_contract_text(raw_axis.get("premium_output")),
            }
        )
    if not expert_axes:
        for raw_unit in list(category_contract.get("reading_units") or [])[:10]:
            if not isinstance(raw_unit, dict):
                continue
            title = _premium_screen_contract_text(raw_unit.get("display_label") or raw_unit.get("label"))
            focus = _premium_screen_contract_text(raw_unit.get("focus"))
            if not title:
                continue
            expert_axes.append(
                {
                    "key": _premium_screen_contract_text(raw_unit.get("topic") or _compact_match_key(title)),
                    "title": title,
                    "customer_question": focus,
                    "verdict_axis": focus,
                    "engine_basis": "격국, 월령, 오행, 십신, 위치 작용을 기준으로 산출한 화면 항목입니다.",
                    "premium_output": _premium_screen_contract_text(raw_unit.get("result") or focus),
                }
            )

    return {
        "schema_version": PREMIUM_SCREEN_ITEM_CONTRACT_SCHEMA_VERSION,
        "domain": domain,
        "section_label": _premium_screen_contract_text(category_contract.get("section_label") or section.get("domain_label")),
        "headline": _premium_screen_contract_text((visual_profile or {}).get("headline") or section.get("lead")),
        "reading_order": [
            _premium_screen_contract_text(item)
            for item in list(category_contract.get("reading_order") or [])
            if _premium_screen_contract_text(item)
        ],
        "summary_slots": summary_slots[:4],
        "screen_items": screen_items[:8],
        "expert_axes": expert_axes,
        "evidence_layers": [
            _premium_screen_contract_text(item)
            for item in list(category_contract.get("evidence_layers") or [])
            if _premium_screen_contract_text(item)
        ],
    }


@lru_cache(maxsize=16384)
def _compact_match_key_cached(text: str) -> str:
    return re.sub(r"[\s·ㆍ\-\(\)]+", "", text)


def _compact_match_key(value: Any) -> str:
    return _compact_match_key_cached(str(value or "").strip())


def _premium_topic_lookup(section: dict[str, Any]) -> dict[str, dict[str, Any]]:
    lookup: dict[str, dict[str, Any]] = {}
    for topic in section.get("topic_items") or []:
        if not isinstance(topic, dict):
            continue
        title = str(topic.get("title") or "").strip()
        if not title:
            continue
        lookup[title] = topic
        lookup[_compact_match_key(title)] = topic
    return lookup


def _find_premium_topic(
    lookup: dict[str, dict[str, Any]],
    topic_title: Any,
    label: Any,
) -> dict[str, Any]:
    candidates = [str(topic_title or "").strip(), str(label or "").strip()]
    for candidate in candidates:
        if candidate and candidate in lookup:
            return lookup[candidate]
        compact = _compact_match_key(candidate)
        if compact and compact in lookup:
            return lookup[compact]
    for candidate in candidates:
        compact = _compact_match_key(candidate)
        if not compact:
            continue
        for key, topic in lookup.items():
            if compact in _compact_match_key(key) or _compact_match_key(key) in compact:
                return topic
    return {}


def _premium_reading_unit_topic(
    section: dict[str, Any],
    lookup: dict[str, dict[str, Any]],
    raw_unit: dict[str, Any],
    label: str,
) -> dict[str, Any]:
    topic = _find_premium_topic(lookup, raw_unit.get("topic"), label)
    if topic:
        return topic
    domain = _domain_key(section)
    topic_title = str(raw_unit.get("topic") or "").strip()
    combined = f"{topic_title} {label}"
    if domain == "timing" and "사건 주제" in combined:
        return _find_premium_topic(lookup, "두드러지는 영역", "주요 분야")
    if domain == "timing" and "과거 대조" in combined:
        return _find_premium_topic(lookup, "지나온 연도", "과거 대조")
    return {}


def _premium_reading_units(section: dict[str, Any], contract: dict[str, Any]) -> list[dict[str, Any]]:
    lookup = _premium_topic_lookup(section)
    units: list[dict[str, Any]] = []
    for raw_unit in contract.get("reading_units") or []:
        if not isinstance(raw_unit, dict):
            continue
        label = str(raw_unit.get("label") or "").strip()
        focus = str(raw_unit.get("focus") or "").strip()
        topic = _premium_reading_unit_topic(section, lookup, raw_unit, label)
        if not label:
            continue
        result = str(topic.get("body") or topic.get("definition") or "").strip()
        unit: dict[str, Any] = {
            "label": label,
            "display_label": str(raw_unit.get("display_label") or label).strip(),
            "topic": str(raw_unit.get("topic") or label).strip(),
            "focus": focus,
            "result": result or focus,
            "value": str(topic.get("value") or "").strip(),
            "tone": str(topic.get("tone") or "neutral"),
        }
        if topic.get("score") is not None:
            unit["score"] = topic.get("score")
        units.append(unit)
    return units


def _premium_unit_strength(unit: dict[str, Any]) -> int:
    score = unit.get("score")
    if isinstance(score, int):
        return max(0, min(100, score))
    return _section_value_strength(str(unit.get("value") or ""))


def _premium_unit_has_profile_signal(unit: dict[str, Any]) -> bool:
    if isinstance(unit.get("score"), int):
        return True
    if str(unit.get("value") or "").strip():
        return True
    return any(str(unit.get(key) or "").strip() for key in ("result", "body", "text", "focus"))


def _premium_unit_is_watch(unit: dict[str, Any]) -> bool:
    strength = _premium_unit_strength(unit)
    tone = str(unit.get("tone") or "")
    value = str(unit.get("value") or "")
    has_metric_value = isinstance(unit.get("score"), int) or bool(value.strip())
    label_text = " ".join(str(unit.get(key) or "") for key in ("label", "display_label", "title"))
    joined = " ".join(
        str(unit.get(key) or "")
        for key in ("label", "display_label", "title", "result", "body", "text", "focus", "value")
    )
    if (
        has_metric_value
        and strength >= 58
        and tone not in {"watch", "risk"}
        and any(marker in label_text for marker in ("방어", "안정성", "통제력", "운영력", "확보력"))
        and not any(marker in label_text for marker in ("부적합", "주의", "위험", "리스크"))
    ):
        return False
    return (has_metric_value and strength < 58) or tone in {"watch", "risk"} or any(
        marker in f"{value} {joined}"
        for marker in (
            "주의",
            "약세",
            "낮음",
            "부적합",
            "갈등",
            "손상",
            "위험",
            "리스크",
            "피해야",
            "권한 없이",
            "결정권이 없는",
        )
    )


def _premium_profile_third_label(unit: dict[str, Any]) -> str:
    if _premium_unit_is_watch(unit):
        return "주의점"
    if _premium_unit_strength(unit) >= 76:
        return "추가 강점"
    return "추가 내용"


def _premium_profile_third_tone(unit: dict[str, Any]) -> str:
    if _premium_unit_is_watch(unit):
        return "watch"
    if _premium_unit_strength(unit) >= 76:
        return "strong"
    return str(unit.get("tone") or "neutral")


def _premium_profile_grade(unit: dict[str, Any]) -> str:
    value = str(unit.get("value") or "")
    if _premium_unit_is_watch(unit):
        return value if value in {"주의 필요", "약세", "낮음"} else "주의 필요"
    return value


def _premium_unit_label(unit: dict[str, Any], fallback: str = "핵심 기준") -> str:
    return _premium_sentence_axis_label(unit.get("display_label") or unit.get("label") or fallback)


def _premium_unit_text(unit: dict[str, Any], fallback: str = "") -> str:
    text = str(unit.get("result") or unit.get("focus") or "").strip()
    return text or fallback


